export class DashboardComponent {
  constructor(dataService) {
    this.dataService = dataService;
    this.summary = null;
    this.members = [];
    this.transactions = [];
    this.loading = true;
    this.error = '';
    this.resultChart = null;
    this.dateChart = null;
    this.pieChart = null;
  }
  ngOnInit() {
    this.loadData();
  }
  ngAfterViewInit() {}
  ngOnDestroy() {
    this.destroyCharts();
  }
  destroyCharts() {
    if (this.resultChart) {
      this.resultChart.destroy();
      this.resultChart = null;
    }
    if (this.dateChart) {
      this.dateChart.destroy();
      this.dateChart = null;
    }
    if (this.pieChart) {
      this.pieChart.destroy();
      this.pieChart = null;
    }
  }
  loadData() {
    this.loading = true;
    this.error = '';
    forkJoin({
      summary: this.dataService.getSummary(),
      members: this.dataService.getMembers(),
      transactions: this.dataService.getTransactions()
    }).subscribe({
      next: data => {
        this.summary = data.summary;
        this.members = data.members;
        this.transactions = data.transactions;
        this.loading = false;
        // Wait for DOM update then draw charts
        setTimeout(() => this.buildCharts(), 50);
      },
      error: err => {
        this.error = 'Failed to load data. Make sure the backend is running on port 3000.';
        this.loading = false;
        console.error(err);
      }
    });
  }
  buildCharts() {
    this.destroyCharts();
    this.buildResultChart();
    this.buildDateChart();
    this.buildPieChart();
  }
  buildResultChart() {
    if (!this.resultChartRef) return;
    const ctx = this.resultChartRef.nativeElement.getContext('2d');
    if (!ctx) return;
    // Sort members by result ascending (most negative first)
    const sorted = [...this.members].sort((a, b) => a.result - b.result);
    const labels = sorted.map(m => m.member);
    const data = sorted.map(m => m.result);
    const colors = data.map(v => v >= 0 ? 'rgba(63, 185, 80, 0.85)' : 'rgba(248, 81, 73, 0.85)');
    const borders = data.map(v => v >= 0 ? '#3fb950' : '#f85149');
    this.resultChart = new Chart(ctx, {
      type: 'bar',
      data: {
        labels,
        datasets: [{
          label: 'Result ($)',
          data,
          backgroundColor: colors,
          borderColor: borders,
          borderWidth: 1,
          borderRadius: 4
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: {
            display: false
          },
          tooltip: {
            callbacks: {
              label: ctx => ` $${ctx.parsed.y.toFixed(2)}`
            },
            backgroundColor: '#1c2128',
            borderColor: '#30363d',
            borderWidth: 1,
            titleColor: '#e6edf3',
            bodyColor: '#8b949e'
          }
        },
        scales: {
          x: {
            ticks: {
              color: '#8b949e',
              font: {
                size: 11
              }
            },
            grid: {
              color: 'rgba(48,54,61,0.5)'
            }
          },
          y: {
            ticks: {
              color: '#8b949e',
              font: {
                size: 11
              },
              callback: v => '$' + v.toLocaleString()
            },
            grid: {
              color: 'rgba(48,54,61,0.5)'
            }
          }
        }
      }
    });
  }
  buildDateChart() {
    if (!this.dateChartRef) return;
    const ctx = this.dateChartRef.nativeElement.getContext('2d');
    if (!ctx) return;
    // Aggregate amounts by date
    const dateMap = new Map();
    for (const t of this.transactions) {
      const cur = dateMap.get(t.date) || 0;
      dateMap.set(t.date, cur + t.amount);
    }
    // Sort dates in chronological order
    const dateOrder = ['Feb 26', 'Mar 5', 'Mar 10', 'Mar 18', 'Mar 20', 'Mar 24', 'Mar 25'];
    const labels = [];
    const data = [];
    for (const d of dateOrder) {
      if (dateMap.has(d)) {
        labels.push(d);
        data.push(parseFloat((dateMap.get(d) || 0).toFixed(2)));
      }
    }
    this.dateChart = new Chart(ctx, {
      type: 'bar',
      data: {
        labels,
        datasets: [{
          label: 'Total Amount ($)',
          data,
          backgroundColor: 'rgba(31, 111, 235, 0.7)',
          borderColor: '#388bfd',
          borderWidth: 1,
          borderRadius: 4
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: {
            display: false
          },
          tooltip: {
            callbacks: {
              label: ctx => ` $${ctx.parsed.y.toFixed(2)}`
            },
            backgroundColor: '#1c2128',
            borderColor: '#30363d',
            borderWidth: 1,
            titleColor: '#e6edf3',
            bodyColor: '#8b949e'
          }
        },
        scales: {
          x: {
            ticks: {
              color: '#8b949e',
              font: {
                size: 12
              }
            },
            grid: {
              color: 'rgba(48,54,61,0.5)'
            }
          },
          y: {
            ticks: {
              color: '#8b949e',
              font: {
                size: 11
              },
              callback: v => '$' + v.toLocaleString()
            },
            grid: {
              color: 'rgba(48,54,61,0.5)'
            }
          }
        }
      }
    });
  }
  buildPieChart() {
    if (!this.pieChartRef) return;
    const ctx = this.pieChartRef.nativeElement.getContext('2d');
    if (!ctx) return;
