    const memberMap = new Map();
    for (const t of this.transactions) {
      const cur = memberMap.get(t.name) || 0;
      memberMap.set(t.name, cur + Math.abs(t.amount));
    }
    const entries = Array.from(memberMap.entries()).sort((a, b) => b[1] - a[1]);
    const labels = entries.map(e => e[0]);
    const data = entries.map(e => parseFloat(e[1].toFixed(2)));
    const palette = ['#388bfd', '#3fb950', '#f85149', '#d29922', '#bc8cff', '#39d353', '#79c0ff', '#ffb86c', '#ff6e96', '#56d364', '#ffa657', '#db61a2'];
    this.pieChart = new Chart(ctx, {
      type: 'doughnut',
      data: {
        labels,
        datasets: [{
          data,
          backgroundColor: palette.slice(0, labels.length),
          borderColor: '#1c2128',
          borderWidth: 2,
          hoverOffset: 6
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        cutout: '60%',
        plugins: {
          legend: {
            position: 'right',
            labels: {
              color: '#8b949e',
              font: {
                size: 11
              },
              padding: 12,
              usePointStyle: true,
              pointStyleWidth: 8
            }
          },
          tooltip: {
            callbacks: {
              label: ctx => ` ${ctx.label}: $${ctx.parsed.toFixed(2)}`
            },
            backgroundColor: '#1c2128',
            borderColor: '#30363d',
            borderWidth: 1,
            titleColor: '#e6edf3',
            bodyColor: '#8b949e'
          }
        }
      }
    });
  }
  // Template helpers
  formatAmount(n) {
    return (n < 0 ? '-$' : '$') + Math.abs(n).toLocaleString('en-US', {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    });
  }
  getTopMembers() {
    return [...this.members].sort((a, b) => Math.abs(b.result) - Math.abs(a.result)).slice(0, 5);
  }
  getMemberInitials(name) {
    return name.slice(0, 2).toUpperCase();
  }
  getTransactionsByDate() {
    const map = new Map();
    for (const t of this.transactions) {
      const cur = map.get(t.date) || {
        count: 0,
        total: 0
      };
      map.set(t.date, {
        count: cur.count + 1,
        total: cur.total + t.amount
      });
    }
    const order = ['Feb 26', 'Mar 5', 'Mar 10', 'Mar 18', 'Mar 20', 'Mar 24', 'Mar 25'];
    return order.filter(d => map.has(d)).map(d => ({
      date: d,
      ...map.get(d)
    }));
  }
